  1→/**
  2→ * Asset service for API calls
  3→ * Feature: 029-asset-bulk-operations
  4→ *
  5→ * Provides methods for:
  6→ * - User Story 1: Bulk delete assets
  7→ * - User Story 2: Export assets to Excel
  8→ * - User Story 3: Import assets from Excel
  9→ */
 10→
 11→import { authenticatedDelete, authenticatedGet, authenticatedPost } from '../utils/auth';
 12→
 13→/**
 14→ * Response from bulk delete operation
 15→ */
 16→export interface BulkDeleteResult {
 17→  deletedAssets: number;
 18→  deletedVulnerabilities: number;
 19→  deletedScanResults: number;
 20→  message: string;
 21→}
 22→
 23→/**
 24→ * Response from import operation
 25→ */
 26→export interface ImportResult {
 27→  message: string;
 28→  imported: number;
 29→  skipped: number;
 30→  assetsCreated?: number;
 31→  assetsUpdated?: number;
 32→  errors?: string[];
 33→}
 34→
 35→/**
 36→ * Delete all assets (ADMIN only)
 37→ * User Story 1: Bulk Delete Assets
 38→ *
 39→ * @returns BulkDeleteResult with counts of deleted entities
 40→ * @throws Error on 403 (forbidden), 409 (conflict), 500 (server error)
 41→ */
 42→export async function bulkDeleteAssets(): Promise<BulkDeleteResult> {
 43→  const response = await authenticatedDelete('/api/assets/bulk');
 44→
 45→  if (response.ok) {
 46→    return await response.json();
 47→  }
 48→
 49→  // Handle error responses
 50→  if (response.status === 403) {
 51→    throw new Error('Insufficient permissions. ADMIN role required.');
 52→  }
 53→
 54→  if (response.status === 409) {
 55→    const error = await response.json();
 56→    throw new Error(error.error || 'Bulk asset deletion already in progress');
 57→  }
 58→
 59→  if (response.status === 500) {
 60→    const error = await response.json();
 61→    throw new Error(error.error || 'Bulk delete failed. No assets were deleted.');
 62→  }
 63→
 64→  throw new Error(`Failed to delete assets: ${response.status}`);
 65→}
 66→
 67→/**
 68→ * Export all accessible assets to Excel file
 69→ * User Story 2: Export Assets to File
 70→ *
 71→ * @returns Blob containing Excel file
 72→ * @throws Error on 400 (no data), 401 (unauthorized), 500 (server error)
 73→ */
 74→export async function exportAssets(): Promise<Blob> {
 75→  const response = await authenticatedGet('/api/assets/export');
 76→
 77→  if (response.ok) {
 78→    return await response.blob();
 79→  }
 80→
 81→  // Handle error responses
 82→  if (response.status === 400) {
 83→    const error = await response.json();
 84→    throw new Error(error.error || 'No assets available to export');
 85→  }
 86→
 87→  if (response.status === 401) {
 88→    throw new Error('Unauthorized. Please login again.');
 89→  }
 90→
 91→  if (response.status === 500) {
 92→    const error = await response.json();
 93→    throw new Error(error.error || 'Failed to export assets');
 94→  }
 95→
 96→  throw new Error(`Failed to export assets: ${response.status}`);
 97→}
