103→ * @param file Excel file to import
104→ * @returns ImportResult with imported/skipped counts and errors
105→ * @throws Error on 400 (validation errors), 401 (unauthorized), 500 (server error)
106→ */
107→export async function importAssets(file: File): Promise<ImportResult> {
108→  const formData = new FormData();
109→  formData.append('xlsxFile', file);
110→
111→  const response = await authenticatedPost('/api/import/upload-assets-xlsx', formData, {
112→    // Don't set Content-Type header - browser will set it with boundary for multipart/form-data
113→    headers: {}
114→  });
115→
116→  if (response.ok) {
117→    return await response.json();
118→  }
119→
120→  // Handle error responses
121→  if (response.status === 400) {
122→    const error = await response.json();
123→    throw new Error(error.error || 'Invalid file format or validation errors');
124→  }
125→
126→  if (response.status === 401) {
127→    throw new Error('Unauthorized. Please login again.');
128→  }
129→
130→  if (response.status === 500) {
131→    const error = await response.json();
132→    throw new Error(error.error || 'Failed to import assets');
133→  }
134→
135→  throw new Error(`Failed to import assets: ${response.status}`);
136→}
